function solve(nums, edges) {
    const N = nums.length;

    // 1. Graph Representation (Adjacency Matrix)
    const adj = Array(N).fill(0).map(() => Array(N).fill(false));
    for (const [u, v] of edges) {
        adj[u][v] = true;
        adj[v][u] = true;
    }

    let count = 0;

    // 2. Iterate Subsets (Masks from 1 to 2^N - 1)
    const totalSubsets = 1 << N;
    for (let mask = 1; mask < totalSubsets; mask++) {

        // --- Step 1: Calculate Sum and Subset Size ---
        let sum = 0;
        let setBits = 0;
        const members = [];

        for (let i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
                setBits++;
                sum += nums[i];
                members.push(i);
            }
        }

        // Check Condition 2: Sum Parity Check
        if (sum % 2 !== 0) {
            continue;
        }

        // --- Step 2: Connectivity Check ---

        // If the subset has only one node, it's trivially connected.
        if (setBits === 1) {
            count++;
            continue;
        }

        // Use BFS starting from the first node in the subset
        const startNode = members[0];
        const queue = [startNode];
        const visited = new Array(N).fill(false);
        visited[startNode] = true;
        let reachedCount = 1;

        let head = 0;
        while (head < queue.length) {
            const u = queue[head++];

            for (let v = 0; v < N; v++) {
                // Check 1: Is v in the subset S (mask)?
                const vInS = (mask >> v) & 1;

                // Check 2: Is there an edge between u and v?
                const edgeExists = adj[u][v];

                // Check 3: Has v not been visited?
                if (vInS && edgeExists && !visited[v]) {
                    visited[v] = true;
                    reachedCount++;
                    queue.push(v);
                }
            }
        }

        // Check Condition 1: Connectivity
        if (reachedCount === setBits) {
            count++;
        }
    }

    return count;
}

