using namespace std;

long long solve(std::vector<long long> nums, std::vector<std::vector<long long>> edges) {
    int N = nums.size();

    // 1. Graph Representation (Adjacency Matrix)
    // Using vector<vector<bool>> for adjacency matrix
    std::vector<std::vector<bool>> adj(N, std::vector<bool>(N, false));
    for (const auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        adj[u][v] = true;
        adj[v][u] = true;
    }

    long long count = 0;

    // 2. Iterate Subsets (Masks from 1 to 2^N - 1)
    int totalSubsets = 1 << N;
    for (int mask = 1; mask < totalSubsets; mask++) {

        // --- Step 1: Calculate Sum and Subset Size ---
        long long sum = 0;
        int setBits = 0;
        std::vector<int> members;

        for (int i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
                setBits++;
                sum += nums[i];
                members.push_back(i);
            }
        }

        // Check Condition 2: Sum Parity Check
        if (sum % 2 != 0) {
            continue;
        }

        // --- Step 2: Connectivity Check ---

        // If the subset has only one node, it's trivially connected.
        if (setBits == 1) {
            count++;
            continue;
        }

        // Use BFS starting from the first node in the subset
        int startNode = members[0];
        std::queue<int> q;
        std::vector<bool> visited(N, false);

        q.push(startNode);
        visited[startNode] = true;
        int reachedCount = 1;

        while (!q.empty()) {
            int u = q.front();
            q.pop();

            // Iterate over all potential neighbors v
            for (int v = 0; v < N; v++) {

                // Check 1: Is v in the subset S (mask)?
                bool vInS = (mask >> v) & 1;

                // Check 2: Is there an edge between u and v?
                bool edgeExists = adj[u][v];

                // Check 3: Has v not been visited?
                if (vInS && edgeExists && !visited[v]) {
                    visited[v] = true;
                    reachedCount++;
                    q.push(v);
                }
            }
        }

        // Check Condition 1: Connectivity
        if (reachedCount == setBits) {
            count++;
        }
    }

    return count;
}

