function solve(nums, edges) {
    const N = nums.length;

    // 1. Graph Representation (Adjacency Matrix)
    const adj = Array(N).fill(0).map(() => Array(N).fill(false));
    for (const [u, v] of edges) {
        adj[u][v] = true;
        adj[v][u] = true;
    }

    let count = 0;

    // Helper function to count set bits (population count)
    const popcount = (n) => {
        let count = 0;
        while (n > 0) {
            n &= (n - 1);
            count++;
        }
        return count;
    };

    // 2. Iterate Subsets (Masks from 1 to 2^N - 1)
    const totalSubsets = 1 << N;
    for (let mask = 1; mask < totalSubsets; mask++) {

        // --- Condition 1: Sum Parity Check ---
        let sum = 0;
        let setBits = 0;
        const members = [];

        for (let i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
