                members.push(i);
            }
        }

        // Check if sum is even
        if (sum % 2 !== 0) {
            continue;
        }

        // --- Condition 2: Connectivity Check ---

        // If the subset has only one node, it's trivially connected.
        if (setBits === 1) {
            count++;
            continue;
        }

        // Use BFS starting from the first node in the subset (members[0])
        const startNode = members[0];
        const queue = [startNode];
        const visited = new Array(N).fill(false);
        visited[startNode] = true;
        let reachedCount = 1;

        let head = 0;
        while (head < queue.length) {
            const u = queue[head++];

            for (let v = 0; v < N; v++) {
                // Check 1: Is v in the subset S (mask)?
                const vInS = (mask >> v) & 1;

                // Check 2: Is there an edge between u and v?
                const edgeExists = adj[u][v];

                // Check 3: Has v not been visited?
                if (vInS && edgeExists && !visited[v]) {
                    visited[v] = true;
                    reachedCount++;
                    queue.push(v);
                }
            }
        }

        // If the number of reached nodes equals the total size of the subset, it is connected.
        if (reachedCount === setBits) {
